// Log payload brut et stocker pour fallback erreur
const lead = $input.first().json;
console.log('RAW_LEAD:', JSON.stringify(lead));

const staticData = $getWorkflowStaticData('global');
staticData.lastLead = JSON.stringify(lead);
staticData.lastLeadTime = new Date().toISOString();

return $input.all();

// Normalise les champs du formulaire WordPress
// Compatible CF7, WPForms, Elementor, Gravity Forms
const raw = $input.first().json;

// Chercher les champs par noms courants (case-insensitive)
const find = (keys) => {
  for (const key of Object.keys(raw)) {
    if (keys.includes(key.toLowerCase())) return raw[key];
  }
  return null;
};

const name = find(['name', 'nom', 'your-name', 'full_name', 'fullname', 'prenom', 'first_name'])
  || find(['your_name', 'field_name', 'wpforms[fields][0]'])
  || 'Prospect';

const phone = find(['phone', 'tel', 'telephone', 'your-phone', 'mobile', 'phone_number'])
  || find(['your_tel', 'field_phone', 'wpforms[fields][2]'])
  || null;

const email = find(['email', 'mail', 'your-email', 'e-mail', 'email_address'])
  || find(['your_email', 'field_email', 'wpforms[fields][1]'])
  || null;

const message = find(['message', 'demande', 'your-message', 'description', 'comments', 'details'])
  || find(['your_message', 'field_message', 'wpforms[fields][3]', 'textarea-1'])
  || '';

return [{
  json: {
    name,
    phone,
    email,
    message,
    raw
  }
}];

// Extraire le message Claude et tronquer a 155 chars
const claudeOutput = $json.content?.[0]?.text || '';
const sms = claudeOutput.length > 155
  ? claudeOutput.substring(0, 152) + '...'
  : claudeOutput;

return [{
  json: {
    name: $('Code: Normalize Fields').first().json.name,
    phone: $('Code: Normalize Fields').first().json.phone,
    email: $('Code: Normalize Fields').first().json.email,
    message: $('Code: Normalize Fields').first().json.message,
    sms,
    raw: $('Code: Normalize Fields').first().json.raw
  }
}];

// Notification dirigeant avec lien tel: pour rappel en 1 clic
const name = $json.name || 'Prospect';
const message = $json.message || '';
const phone = $json.phone || null;
const email = $json.email || 'non fourni';

let ownerSms;
if (phone) {
  ownerSms = `Nouveau lead: ${name}\n"${message.substring(0, 60)}"\nAppeler: tel:${phone}`;
} else {
  ownerSms = `Nouveau lead: ${name}\n"${message.substring(0, 60)}"\nEmail: ${email}\n(Pas de tel)`;
}

return [{
  json: {
    ...($input.first().json),
    owner_sms: ownerSms.substring(0, 320)
  }
}];

// Verifier heures ouvrables (lun-sam 08h-20h, Paris)
const now = $now.setZone('Europe/Paris');
const ok = now.weekday >= 1 && now.weekday <= 6 && now.hour >= 8 && now.hour < 20;
return [{ json: { ...$input.first().json, business_hours_ok: ok } }];

// Recuperer le dernier lead depuis staticData et envoyer en fallback
const staticData = $getWorkflowStaticData('global');
let fallback = 'ERREUR Speed to Lead — pas de donnees lead disponibles.';

try {
  if (staticData.lastLead) {
    const lead = JSON.parse(staticData.lastLead);
    const name = lead.name || lead.nom || 'Inconnu';
    const phone = lead.phone || lead.tel || 'N/A';
    const email = lead.email || 'N/A';
    fallback = `ERREUR Speed to Lead\nLead: ${name}\nTel: ${phone}\nEmail: ${email}\nTraiter manuellement.`;
  }
} catch(e) {
  fallback = `ERREUR Speed to Lead — donnees corrompues: ${staticData.lastLead?.substring(0, 80)}`;
}

return [{ json: { fallback_sms: fallback.substring(0, 320) } }];
